const API = '';
const LS_USER = 'humanx_public_user_v1';
const LS_ADMIN = 'humanx_admin_token_v1';

let claims = [];
let evidenceVault = [];
let truths = [];
let beliefSnapshots = [];
let graphStatus = null;
let selected = null;
let mode = 'home';
let lastPacket = '';
let live = false;
let user = null;
let lastBeliefSnapshot = null;
let reviewQueue = { claims: [], truths: [], review: [] };
let inspectedReviewItem = null;
let reviewStateFilter = 'review';
let attachingEvidenceId = null;

function esc(s) {
  return String(s ?? '').replace(/[&<>"']/g, m => ({
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#039;'
  }[m]));
}
function toast(t) { const e=document.createElement('div'); e.className='toast'; e.textContent=t; document.body.appendChild(e); setTimeout(()=>e.remove(),1800); }
function headers(){return{'content-type':'application/json','x-humanx-user':user?.id||''}}
function adminToken(){return localStorage.getItem(LS_ADMIN)||''}
function adminHeaders(){return {...headers(),'x-humanx-admin':adminToken()}}
async function api(path,opts={}){const r=await fetch(API+path,{...opts,headers:{...headers(),...(opts.headers||{})}});const data=await r.json().catch(()=>({}));if(!r.ok)throw new Error(data.message||data.error||'Request failed');return data}
function localUser(){let u=JSON.parse(localStorage.getItem(LS_USER)||'null');if(!u){u={id:'usr_'+crypto.randomUUID().replaceAll('-','').slice(0,18),handle:'anon-'+Math.random().toString(36).slice(2,8)};localStorage.setItem(LS_USER,JSON.stringify(u))}return u}
function sourceLink(url){if(!url)return'';const safe=esc(url);return`<p class="small source"><a href="${safe}" target="_blank" rel="noopener noreferrer">${safe}</a></p>`}
function cleanStance(v){v=String(v||'support').toLowerCase().trim();return v==='pressure'?'pressure':'support'}
function cleanClaimLabel(s){return String(s||'').replace(/\s*[—-]\s*this statement reflects reality consistently enough to survive evidence and repeatable pressure testing\.?/ig,'').replace(/\s*[—-]\s*X\s*$/,'').trim()}
function isFullBeliefProfile(s){return String(s?.source||'').includes('standalone-humanx-belief-engine')||String(s?.engineVersion||'').includes('humanx-belief-engine')||String(s?.label||'').includes('Belief Engine Profile')}
function parseAnalysis(text){try{const o=JSON.parse(String(text||''));if(o&&typeof o==='object'&&(o.verdict||o.strongest_support||o.strongest_pressure||o.missing_tests))return o}catch{}return null}
function shortText(s,n=420){s=String(s||'').trim();return s.length>n?s.slice(0,n)+'…':s}
function listBits(arr){return Array.isArray(arr)?`<ul>${arr.slice(0,4).map(x=>`<li>${esc(x)}</li>`).join('')}</ul>`:''}
async function boot(){user=localUser();document.getElementById('who').textContent=user.handle;try{const h=await api('/api/health');live=h.mode==='d1-live';setStatus(live?'D1 live':'Demo fallback',live);try{const s=await api('/api/session',{method:'POST',body:JSON.stringify(user)});if(s.user){user={...user,...s.user};document.getElementById('who').textContent=user.handle;localStorage.setItem(LS_USER,JSON.stringify(user))}}catch{}await Promise.all([loadGraphStatus(),loadClaims(false)]);render()}catch(e){setStatus('Backend unreachable',false,true);renderError(e)}}
function setStatus(t,ok,bad=false){document.getElementById('status').textContent=t;const d=document.getElementById('dot');d.className='dot '+(bad?'bad':ok?'live':'')}
async function loadGraphStatus(){try{graphStatus=await api('/api/graph-status')}catch{graphStatus=null}}
function q(){return encodeURIComponent(document.getElementById('search')?.value||'')}
async function loadClaims(doRender=true){try{const f=encodeURIComponent(document.getElementById('filter')?.value||'all');const data=await api(`/api/claims?q=${q()}&status=${f}`);claims=data.claims||[];if(data.warning)setStatus(data.warning,false);if(doRender)render()}catch(e){renderError(e)}}
async function loadEvidenceVault(){const data=await api(`/api/evidence-vault?q=${q()}`);evidenceVault=data.evidence||[]}
async function loadTruths(){const data=await api(`/api/truths?q=${q()}`);truths=data.truths||[]}
async function loadBeliefSnapshots(){const data=await api('/api/belief-snapshots?limit=30');beliefSnapshots=data.snapshots||[]}
async function loadReviewQueue(){const data=await api('/api/review',{headers:adminHeaders()});reviewQueue={claims:data.claims||[],truths:data.truths||[],review:data.review||[]};return reviewQueue}
async function searchCurrent(){if(mode==='vault')return renderVault();if(mode==='truths')return renderTruths();if(mode==='review')return renderReview();if(mode==='belief')return renderBelief();if(mode==='drift')return renderDrift();if(mode==='home')return renderHome();await loadClaims(true)}
function setMode(m){mode=m;if(m!=='export')selected=null;document.body.classList.remove('study-mode');document.querySelectorAll('.tab').forEach(x=>x.classList.remove('active'));document.getElementById('tab-'+m)?.classList.add('active');render()}
function cls(s){if(s==='Proven'||String(s).includes('Supported')||String(s).includes('rising'))return'b-green';if(String(s).includes('Disproven')||String(s).includes('Collapse')||String(s).includes('falling'))return'b-red';if(s==='Plausible')return'b-blue';return'b-yellow'}
function meter(n,v){v=Math.max(0,Math.min(100,Number(v||0)));return`<div class="meter"><span>${n}</span><div class="bar"><div class="fill" style="width:${v}%"></div></div></div>`}
function deltaMeter(n,v){const sign=v>0?'+':'';return`<div class="meter"><span>${n} ${sign}${esc(v)}</span><div class="bar"><div class="fill" style="width:${Math.min(100,Math.abs(Number(v||0)))}%"></div></div></div>`}
function graphVal(v){return v===null||v===undefined?'ERR':v}
function graphBox(){const g=graphStatus?.graph||{};const items=[['Claims',g.claims],['Evidence',g.evidence],['Truths',g.truths],['Links',g.evidenceClaimLinks],['Votes',g.claimVotes],['Reports',g.reports]];const err=graphStatus&&graphStatus.ok===false?`<p class="small error">Graph schema warning: ${esc(Object.keys(graphStatus.errors||{}).join(', ')||'unknown')}</p>`:'';return`<div class="graph-status">${items.map(([k,v])=>`<span><b>${esc(graphVal(v))}</b><small>${k}</small></span>`).join('')}</div>${err}`}
function helperText(){if(mode==='drift')return'<p class="small">Drift separates full Belief Engine profiles from quick belief records.</p>';if(mode==='belief')return'<p class="small">Belief Engine: record belief structure, source, identity load, inheritance, pressure, and what could change your mind.</p>';if(mode==='home')return'<p class="small">Map personal belief. Record repeated truths. Pressure-test public claims. Reuse evidence across the pipeline.</p>'+graphBox();if(mode==='vault')return'<p class="small">Reusable evidence, claim links, truth bridges, and belief-origin records live here. Use this vault to trace how a claim is supported, challenged, reused, or promoted across HumanX.</p>'+graphBox();if(mode==='truths')return'<p class="small">Truths: repeated certainties, slogans and doctrines. Convert useful ones into pressure-testable claims.</p>'+graphBox();if(mode==='review')return'<p class="small">Admin moderation queue. Items in review are not yet public and not yet rejected. Approve to publish, reject to hide, keep in review to hold. Requires HUMANX_ADMIN_TOKEN.</p>'+graphBox();if(mode==='export')return selected?`<p class="small">Selected for RunPack:<br><b>${esc(selected.claim)}</b></p><p class="small">Paste into any AI for analysis.</p>`:'<p class="small">No claim selected. Open a claim from Claims, then return here to generate its RunPack.</p>';if(mode==='submit')return'<p class="small">Submit one public claim. State it precisely — it will be tested with evidence and pressure.</p>';return'<p class="small">Claims: public pressure-testable statements. Open Study to inspect evidence, attacks, tests, votes, and RunPack.</p>'+graphBox()}
function render(){if(mode==='home')return renderHome();if(mode==='belief')return renderBelief();if(mode==='drift')return renderDrift();if(mode==='submit')return renderSubmit();if(mode==='vault')return renderVault();if(mode==='truths')return renderTruths();if(mode==='review')return renderReview();if(mode==='export')return renderExport();renderArena()}
function renderHome(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';const g=graphStatus?.graph||{};const sv=v=>v===null||v===undefined?'unknown':String(v);document.getElementById('main').innerHTML=`<div class="cc-layout"><section class="cc-hero"><div class="cc-hero-left"><span class="badge b-green">working system</span><h1 class="cc-title">HumanX</h1><p class="cc-subtitle">Map personal belief. Record repeated truths. Pressure-test public claims. Reuse evidence across the pipeline. Separate confidence from proof.</p><div class="pipeline-banner"><div class="pipeline-stage"><b>Beliefs</b><span>personal structure</span></div><div class="pipeline-arrow">→</div><div class="pipeline-stage"><b>Truths</b><span>repeated certainties</span></div><div class="pipeline-arrow">→</div><div class="pipeline-stage"><b>Claims</b><span>public statements</span></div><div class="pipeline-arrow">→</div><div class="pipeline-stage"><b>Evidence</b><span>support &amp; challenge</span></div><div class="pipeline-arrow">→</div><div class="pipeline-stage"><b>RunPack</b><span>export for AI analysis</span></div></div></div><div class="cc-hero-right">${graphBox()}</div></section><section class="cc-section"><h2 class="cc-section-head">Current System State</h2><div class="cc-stat-grid"><div class="cc-stat"><span class="cc-stat-label">User</span><span class="cc-stat-val">${esc(user?.handle||'anonymous')}</span></div><div class="cc-stat"><span class="cc-stat-label">Backend</span><span class="cc-stat-val">${esc(live?'D1 live':(graphStatus!==null?'Demo fallback':'Not loaded'))}</span></div><div class="cc-stat"><span class="cc-stat-label">Claims loaded</span><span class="cc-stat-val">${claims.length>0?claims.length:sv(g.claims)}</span></div><div class="cc-stat"><span class="cc-stat-label">Graph evidence</span><span class="cc-stat-val">${sv(g.evidence)}</span></div><div class="cc-stat"><span class="cc-stat-label">Graph truths</span><span class="cc-stat-val">${sv(g.truths)}</span></div><div class="cc-stat"><span class="cc-stat-label">Graph links</span><span class="cc-stat-val">${sv(g.evidenceClaimLinks)}</span></div></div></section><section class="cc-section"><h2 class="cc-section-head">Actions</h2><div class="cc-card-grid"><button class="cc-card cc-card-primary" onclick="location.href='/apps/humanx-belief-engine/'"><span class="cc-card-icon">◉</span><b>Belief Engine</b><span class="cc-card-desc">Full 77-statement forensic belief profile. Maps belief structure, source, identity load, inheritance, pressure, and what could change your mind.</span><span class="cc-card-when">When: starting from personal belief before making a public claim.</span><span class="cc-card-action">Open Belief Engine →</span></button><button class="cc-card" onclick="setMode('drift')"><span class="cc-card-icon">〜</span><b>Drift</b><span class="cc-card-desc">View full Belief Engine profiles and quick belief records over time. Measure belief drift across sessions.</span><span class="cc-card-when">When: comparing beliefs over time or reviewing saved profile snapshots.</span><span class="cc-card-action">View Drift →</span></button><button class="cc-card" onclick="setMode('submit')"><span class="cc-card-icon">✦</span><b>Submit Claim</b><span class="cc-card-desc">Submit one precise, pressure-testable public statement. Pseudonymous. Enters moderation before going live.</span><span class="cc-card-when">When: you have a belief or truth ready to test publicly.</span><span class="cc-card-action">Submit Claim →</span></button><button class="cc-card" onclick="setMode('arena')"><span class="cc-card-icon">⊞</span><b>Browse Claims</b><span class="cc-card-desc">Open, study, vote on, and attach evidence to public claims. Enter Study mode for evidence, pressure, tests, and analysis.</span><span class="cc-card-when">When: reviewing, attacking, or supporting existing claims.</span><span class="cc-card-action">Browse Claims →</span></button><button class="cc-card" onclick="setMode('vault')"><span class="cc-card-icon">◈</span><b>Evidence Vault</b><span class="cc-card-desc">Reusable sources, documents, datasets, and test records. Attach vault items across multiple claims without duplication.</span><span class="cc-card-when">When: browsing reusable evidence or tracing how a source is used across claims.</span><span class="cc-card-action">Evidence Vault →</span></button><button class="cc-card" onclick="setMode('truths')"><span class="cc-card-icon">◇</span><b>Truths</b><span class="cc-card-desc">Repeated certainties, slogans, doctrines, and inherited statements. Convert useful ones into pressure-testable claims.</span><span class="cc-card-when">When: recording a widely repeated belief or promoting a truth to a public claim.</span><span class="cc-card-action">View Truths →</span></button><button class="cc-card" onclick="setMode('export')"><span class="cc-card-icon">⊡</span><b>RunPack</b><span class="cc-card-desc">Generate a structured analysis packet from any claim. Paste into any AI for external analysis. No owner API credits used.</span><span class="cc-card-when">When: ready to export a claim for AI analysis after evidence and pressure are attached.</span><span class="cc-card-action">RunPack Export →</span></button></div></section><section class="cc-section cc-workflow-section"><h2 class="cc-section-head">Safe Workflow</h2><div class="cc-workflow"><div class="cc-step"><span class="cc-step-n">1</span><b>Map belief</b><span>Run the Belief Engine. Save your full profile to HumanX via the bridge.</span></div><div class="cc-step-arrow">→</div><div class="cc-step"><span class="cc-step-n">2</span><b>Promote repeated truth</b><span>Record a repeated certainty in Truths. Convert it to a claim when ready to test publicly.</span></div><div class="cc-step-arrow">→</div><div class="cc-step"><span class="cc-step-n">3</span><b>Submit public claim</b><span>State one precise, falsifiable claim. Enters moderation queue before going live.</span></div><div class="cc-step-arrow">→</div><div class="cc-step"><span class="cc-step-n">4</span><b>Attach support / pressure</b><span>Study the claim. Add evidence, contradictions, and tests.</span></div><div class="cc-step-arrow">→</div><div class="cc-step"><span class="cc-step-n">5</span><b>Export RunPack</b><span>Generate a RunPack. Paste into any AI. Save the JSON result back to the claim.</span></div></div></section></div>`}
async function renderBelief(){location.href='/apps/humanx-belief-engine/'}
async function renderDrift(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML='<div class="panel"><h2>Loading Drift…</h2></div>';try{await loadBeliefSnapshots()}catch(e){beliefSnapshots=[]}const ordered=[...beliefSnapshots].sort((a,b)=>(a.createdAt||0)-(b.createdAt||0));const profiles=ordered.filter(isFullBeliefProfile);const quick=ordered.filter(s=>!isFullBeliefProfile(s));document.getElementById('main').innerHTML=`<div class="section-head"><h2>Drift</h2><span class="badge b-blue">${profiles.length} full profiles · ${quick.length} quick records</span></div>${profiles.length?renderProfileDrift(profiles):'<div class="panel"><h3>Full Belief Engine Profiles</h3><p class="small">No full profile saved yet. Run the Belief Engine and click Send to HumanX.</p><button class="primary" onclick="location.href=\'/apps/humanx-belief-engine/\'">Open Belief Engine</button></div>'}${quick.length?`<div class="section-head"><h2>Quick Belief Records</h2><span class="badge">${quick.length} records</span></div><div class="grid">${quick.map(beliefSnapshotCard).join('')}</div>`:''}<div class="section-head"><h2>Full Timeline</h2><span class="badge">${ordered.length} total records</span></div><div class="grid">${ordered.map(beliefSnapshotCard).join('')||'<div class="panel">No belief records yet.</div>'}</div>`}
function renderProfileDrift(profiles){const first=profiles[0],last=profiles[profiles.length-1];const ds=(last.stabilityScore||0)-(first.stabilityScore||0),doo=(last.opennessScore||0)-(first.opennessScore||0),dp=(last.pressureScore||0)-(first.pressureScore||0),dc=(last.contradictionCount||0)-(first.contradictionCount||0);const verdict=profiles.length<2?'profile baseline':dp>20?'pressure rising':ds>20?'stability rising':doo>20?'openness rising':ds<-20?'stability falling':'mixed / stable profile drift';return`<div class="section-head"><h2>Full Belief Engine Profiles</h2><span class="badge ${cls(verdict)}">${esc(verdict)}</span></div><div class="panel analysis-card"><h3>${profiles.length<2?'Latest full profile':'Oldest full profile → newest full profile'}</h3><p class="small"><b>From:</b> ${esc(first.label||'profile')}<br><b>To:</b> ${esc(last.label||'profile')}</p><div class="meters">${deltaMeter('Stability',ds)}${deltaMeter('Openness',doo)}${deltaMeter('Pressure',dp)}${deltaMeter('Contradictions',dc)}</div><p class="small">${profiles.length<2?'One full profile saved. Run the Belief Engine again later to measure real profile drift.':driftText(ds,doo,dp,dc)}</p></div><div class="grid">${profiles.map(beliefSnapshotCard).join('')}</div>`}
function driftText(ds,doo,dp,dc){const bits=[];if(ds>10)bits.push('belief stability increased');if(ds<-10)bits.push('belief stability weakened');if(doo>10)bits.push('openness increased');if(doo<-10)bits.push('openness narrowed');if(dp>10)bits.push('pressure increased');if(dp<-10)bits.push('pressure reduced');if(dc>0)bits.push('more contradictions were detected');if(dc<0)bits.push('fewer contradictions were detected');return bits.length?bits.join('; ')+'.':'No major movement detected yet.'}
function beliefSnapshotMini(s){return`<span class="badge b-yellow">${esc(s.dominantPattern||s.source||'belief')}</span><h3>${esc(s.label||'Belief record')}</h3><p class="small">${esc(new Date(s.createdAt||Date.now()).toLocaleString())}</p><div class="meters">${meter('Stability',s.stabilityScore)}${meter('Open',s.opennessScore)}${meter('Pressure',s.pressureScore)}</div><p class="small">${esc(shortText(s.summary||'',300))}</p>`}
function beliefSnapshotCard(s){const full=isFullBeliefProfile(s);return`<article class="card"><span class="badge ${full?'b-blue':'b-yellow'}">${esc(full?'full profile':(s.dominantPattern||s.source||'belief'))}</span><h3>${esc(s.label||'Belief record')}</h3><p class="small">${esc(new Date(s.createdAt||Date.now()).toLocaleString())}</p><div class="meters">${meter('Stability',s.stabilityScore)}${meter('Open',s.opennessScore)}${meter('Pressure',s.pressureScore)}</div><p class="small">${esc(shortText(s.summary||'',260))}</p><div class="actions"><button onclick="promoteBelief('${esc(s.id)}','truth')">Promote → Truth</button><button class="primary" onclick="promoteBelief('${esc(s.id)}','claim')">Promote → Claim</button></div></article>`}
function n(id){return Number(document.getElementById(id)?.value||0)}function v(id){return document.getElementById(id)?.value||''}
function buildBeliefSnapshot(){return{}}
function classifyBelief(){return'open belief'}
function beliefPreview(){}
async function saveBeliefMirror(){location.href='/apps/humanx-belief-engine/'}
async function promoteBelief(snapshotId,target){try{const data=await api('/api/belief-promote',{method:'POST',body:JSON.stringify({snapshotId,target})});if(target==='truth'){toast(data.existing?'Truth reinforced':'Truth created');mode='truths';await loadGraphStatus();await renderTruths();return}if(data.claimId){toast(data.existing?'Existing claim opened':'Claim created');mode='arena';await loadGraphStatus();await loadClaims(false);await selectClaim(data.claimId);return}toast('Belief promoted')}catch(e){toast(e.message||'Could not promote belief')}}
function renderArena(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML=`<div class="section-head"><h2>Claims</h2>${graphBox()}</div><div class="grid">${claims.map(c=>card(c,true)).join('')||'<div class="panel"><div class="empty-state"><p>No claims found.</p><p class="small">Submit the first testable public claim using the Submit tab.</p></div></div>'}</div>`}
function card(c,actions=false){const votes=`<span title="Believe">▲ ${esc(c.beliefYes||0)}</span><span title="Reject">▼ ${esc(c.beliefNo||0)}</span><span title="Unsure">~ ${esc(c.uncertainty||0)}</span>${c.contradictions?`<span title="Pressure points">⊘ ${esc(c.contradictions)}</span>`:''}`;const metaParts=[c.type,c.handle?'by '+c.handle:''].filter(Boolean).map(esc).join(' · ');return`<article class="card claim-card"><div class="claim-card-head"><span class="badge ${cls(c.status)}">${esc(c.status||'unknown')}</span>${c.category?`<span class="claim-cat">${esc(c.category)}</span>`:''}</div><h3 class="claim-title">${esc(cleanClaimLabel(c.claim))}</h3>${metaParts?`<p class="claim-meta small">${metaParts}</p>`:''}<div class="meters">${meter('Evidence',c.evidenceScore)}${meter('Test',c.testability)}${meter('Survive',c.survivability)}</div><div class="claim-votes">${votes}</div>${actions?`<div class="actions"><button class="primary" onclick="selectClaim('${esc(c.id)}')">Study →</button></div>`:''}</article>`}
function renderSubmit(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML=`<div class="panel form-panel"><h2>Submit Claim</h2><p class="small">State one clear, testable claim. No email required. Pseudonymous by default.</p><div class="claimbox"><input id="cClaim" placeholder="Claim"><input id="cCategory" placeholder="Category"><select id="cType"><option>Physical/Testable</option><option>Historical</option><option>Religious/Belief</option><option>Conspiracy</option><option>Product Claim</option><option>Medical/High Risk</option></select><textarea id="cEvidence" placeholder="Initial evidence or reason"></textarea><button class="primary" onclick="saveClaim()">Submit to HumanX</button></div></div>`}
async function renderVault(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML='<div class="panel"><h2>Loading Evidence…</h2></div>';try{await loadEvidenceVault();document.getElementById('casefile').innerHTML=helperText();const count=evidenceVault.length;document.getElementById('main').innerHTML=`<div id="attach-modal" class="attach-modal" style="display:none"></div><div class="vault-header"><div class="vault-header-top"><h2>Evidence Vault</h2><span class="badge b-blue">${count} item${count===1?'':'s'}</span></div><p class="small">Reusable sources, documents, data, and records. Items can be attached to multiple claims as support evidence or pressure attacks. Use the search bar above to find existing evidence before adding a new item.</p>${graphBox()}</div><div class="grid evidence-grid">${evidenceVault.map(e=>evidenceCard(e)).join('')||'<div class="empty-state"><p>No evidence in the vault yet.</p><p class="small">Open a claim in Study mode and use the side panel to add supporting evidence or an attack. Vault items can then be reused across multiple claims.</p></div>'}</div>`}catch(e){renderError(e)}}
function evidenceCard(e){const a=parseAnalysis(e.body);const stance=e.linked_stance||e.stance||'support';const stanceClr=stance==='pressure'||stance==='attack'?'b-red':stance==='support'?'b-green':'b-yellow';const quality=e.quality||'unknown';const qualClr=quality==='repeatable'||quality==='documented'||quality==='media'?'b-blue':quality==='vibes'?'':'b-yellow';const mediaType=e.media_type||e.mediaType||'text';const reliability=e.reliability_score||e.reliabilityScore||null;const date=e.updated_at||e.updatedAt||e.created_at||null;const dateStr=date?new Date(date).toLocaleDateString():null;const reuse=e.reuse_count||e.reuseCount||null;return`<article class="card evidence-card"><div class="vault-card-head"><b class="vault-card-title">${esc(e.title)}</b><div class="vault-card-badges"><span class="badge ${stanceClr}">${esc(stance)}</span><span class="badge ${qualClr}">${a?'analysis':esc(quality)} · ${esc(mediaType)}</span>${reliability?`<span class="pill">reliability ${esc(reliability)}</span>`:''} ${reuse&&reuse>1?`<span class="pill">reused ${esc(reuse)}×</span>`:''}</div></div>${a?analysisSummary(a):`<p class="small vault-card-body">${esc(shortText(e.body||e.note||'',320))}</p>`}${sourceLink(e.sourceUrl||e.source_url)}<div class="vault-card-claim"><span class="pill">linked claim</span><span class="small">${esc(cleanClaimLabel(e.claim||'No linked claim'))}</span><span class="badge ${cls(e.claimStatus)}">${esc(e.claimStatus||'unknown')}</span></div>${dateStr?`<p class="small vault-card-date">Updated ${esc(dateStr)}</p>`:''}<div class="actions">${e.claimId?`<button onclick="selectClaim('${esc(e.claimId)}')">Study Linked Claim</button>`:''}<button class="primary" onclick="attachEvidencePrompt('${esc(e.id)}')">Attach to Claim</button></div></article>`}
function analysisSummary(a){return`<div class="analysis-card"><span class="badge ${cls(a.verdict)}">${esc(a.verdict||'analysis')}</span><div class="meters">${meter('Evidence',a.evidence_score||a.evidenceScore||0)}${meter('Test',a.testability||0)}${meter('Survive',a.survivability||0)}</div><p class="small">${esc(a.plain_language_summary||a.plainLanguageSummary||'Legacy analysis result stored in evidence. New results should be saved in Analysis.')}</p></div>`}
async function renderTruths(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML='<div class="panel"><h2>Loading Truths…</h2></div>';try{await loadTruths();document.getElementById('casefile').innerHTML=helperText();document.getElementById('main').innerHTML=`<div class="section-head"><h2>Truth Statements</h2><span class="badge b-yellow">repeated certainties · slogans · doctrines</span>${graphBox()}</div><div class="panel compact-form"><input id="truthStatement" placeholder="Truth statement, slogan, doctrine or inherited certainty"><input id="truthCategory" placeholder="Category"><input id="truthOrigin" placeholder="Origin"><select id="truthType"><option value="common">Common truth</option><option value="religious">Religious truth</option><option value="political">Political truth</option><option value="scientific">Scientific consensus</option><option value="family">Family truth</option><option value="cultural">Cultural truth</option></select><button class="primary" onclick="submitTruth()">Add Truth</button></div><div class="grid truth-grid">${truths.map(t=>truthCard(t)).join('')||'<div class="panel">No truths recorded yet. Add a repeated certainty, slogan, or inherited doctrine above.</div>'}</div>`}catch(e){renderError(e)}}
function truthCard(t){return`<article class="card truth-card"><span class="badge b-yellow">${esc(t.truthType||'truth')} · ${esc(t.confidenceLabel||'claimed')}</span><h3>${esc(cleanClaimLabel(t.statement))}</h3><p class="small">${esc(t.category||'general')} · ${esc(t.origin||'unknown')} · by ${esc(t.handle||'anon')}</p><div class="meters"><div class="meter"><span>Repeated</span><b>${esc(t.repetitionScore||1)}</b></div><div class="meter"><span>Pressure</span><b>${esc(t.pressureScore||0)}</b></div><div class="meter"><span>Claim</span><b>${t.linkedClaimId?'yes':'no'}</b></div></div><div class="actions"><button class="primary" onclick="convertTruth('${esc(t.id)}')">Convert to Claim</button></div></article>`}
async function renderReview(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';const token=adminToken();document.getElementById('main').innerHTML=`<div class="review-page"><div class="review-header"><div class="review-header-top"><h2>Review Queue</h2><span class="badge b-red">admin only</span></div><p class="small">Approve makes a claim public and visible to all users. Reject hides it. Keep Review leaves it pending. Report count reflects user flags — not proof of wrongdoing.</p></div><div class="panel review-token-panel"><div class="review-token-form"><input id="adminToken" placeholder="Admin token" value="${esc(token)}" autocomplete="off"><button class="primary" onclick="saveAdminTokenAndLoadReview()">Load Queue</button><button onclick="clearAdminToken()">Clear Token</button></div></div><div id="reviewList" class="grid"><div class="panel">${token?'Loading review queue…':'Enter admin token above to load the review queue.'}</div></div></div>`;if(token){try{await loadReviewQueue();renderReviewList()}catch(e){document.getElementById('reviewList').innerHTML=`<div class="panel"><h3>Review unavailable</h3><p class="small">${esc(e.message||e)}</p></div>`}}}
function applyReviewFilter(list){const f=reviewStateFilter||'review';if(f==='all')return list;if(f==='reported')return list.filter(i=>(i.report_count||i.reportCount||0)>0);return list.filter(i=>(i.review_state||i.reviewState||'review')===f)}
function renderReviewFilterBar(list){const s=i=>(i.review_state||i.reviewState||'review');const counts={review:list.filter(i=>s(i)==='review').length,public:list.filter(i=>s(i)==='public').length,rejected:list.filter(i=>s(i)==='rejected').length,reported:list.filter(i=>(i.report_count||i.reportCount||0)>0).length,all:list.length};const defs=[['review','Pending'],['public','Public'],['rejected','Rejected'],['reported','Reported'],['all','All']];const chips=defs.map(([f,label])=>{const n=counts[f];const active=reviewStateFilter===f;return`<button class="review-filter-chip${active?' review-filter-chip-active':''}" onclick="setReviewFilter('${f}')">${label}${n>0?` <span class="review-filter-count">${n}</span>`:''}</button>`}).join('');return`<div class="review-filter-bar" style="grid-column:1/-1">${chips}</div>`}
function setReviewFilter(f){reviewStateFilter=f||'review';renderReviewList()}
function renderReviewList(){const all=reviewQueue.review||[];const list=applyReviewFilter(all);if(inspectedReviewItem&&!list.find(i=>i.id===inspectedReviewItem.id))inspectedReviewItem=null;const bar=renderReviewFilterBar(all);const panel=inspectedReviewItem?renderReviewInspectPanel(inspectedReviewItem):'';const emptyMsgs={review:'No items pending review. All caught up.',public:'No public items in queue.',rejected:'No rejected items.',reported:'No reported items.',all:'Queue is empty.'};const empty=`<div class="panel" style="grid-column:1/-1"><p class="small">${emptyMsgs[reviewStateFilter]||'No items.'}</p></div>`;document.getElementById('reviewList').innerHTML=bar+panel+(list.map(reviewCard).join('')||empty)}
function reviewCard(item){const type=item.target_type||item.targetType||item.type||'claim';const isTruth=type==='truth';const id=item.id;const title=isTruth?(item.statement||'Truth'):(item.claim||'Claim');const state=item.review_state||item.reviewState||'review';const stateClr=state==='public'?'b-green':state==='rejected'?'b-red':'b-yellow';const cardMod=state==='public'?'review-card-public':state==='rejected'?'review-card-rejected':state==='duplicate'?'review-card-duplicate':'review-card-pending';const isSelected=!!(inspectedReviewItem&&inspectedReviewItem.id===id);const reports=item.report_count||item.reportCount||0;const metaParts=[item.category||'general',isTruth?(item.origin||null):(item.status||null)].filter(Boolean);const updated=new Date(item.updated_at||item.updatedAt||item.created_at||Date.now()).toLocaleDateString();return`<article class="card review-card ${cardMod}${isSelected?' review-card-selected':''}"><div class="review-card-head"><span class="badge ${isTruth?'b-yellow':'b-blue'}">${esc(type)}</span><span class="badge ${stateClr}">${esc(state)}</span>${reports>0?`<span class="badge b-red">⚑ ${esc(reports)} report${reports===1?'':'s'}</span>`:''}</div><h3 class="review-card-title">${esc(cleanClaimLabel(title))}</h3><p class="small review-card-meta">${metaParts.map(esc).join(' · ')}</p><p class="small review-card-date">Updated ${esc(updated)}</p><div class="review-actions"><button class="btn-inspect${isSelected?' btn-inspect-active':''}" title="Inspect all available fields" onclick="inspectReviewItem('${esc(id)}')">${isSelected?'▲ Inspecting':'Inspect'}</button><button class="btn-approve" title="Publish this item to all users" onclick="reviewDecisionUI('${esc(type)}','${esc(id)}','public')">Approve Public</button><button class="btn-keep" title="Leave pending for later review" onclick="reviewDecisionUI('${esc(type)}','${esc(id)}','review')">Keep Review</button><button class="btn-reject" title="Hide this item permanently" onclick="reviewDecisionUI('${esc(type)}','${esc(id)}','rejected')">Reject</button></div></article>`}
function inspectReviewItem(id){const item=(reviewQueue.review||[]).find(i=>i.id===id)||null;inspectedReviewItem=(inspectedReviewItem&&inspectedReviewItem.id===id)?null:item;renderReviewList()}
function renderReviewInspectPanel(item){const type=item.target_type||item.targetType||item.type||'claim';const isTruth=type==='truth';const id=item.id;const title=isTruth?(item.statement||'—'):(item.claim||'—');const state=item.review_state||item.reviewState||'review';const stateClr=state==='public'?'b-green':state==='rejected'?'b-red':'b-yellow';const reports=item.report_count||item.reportCount||0;const fields=[];fields.push(['ID',`<code class="review-inspect-id">${esc(id)}</code>`]);fields.push(['Type',`<span class="badge ${isTruth?'b-yellow':'b-blue'}">${esc(type)}</span>`]);fields.push(['State',`<span class="badge ${stateClr}">${esc(state)}</span>`]);if(reports>0)fields.push(['Reports',`<span class="badge b-red">⚑ ${reports} report${reports===1?'':'s'}</span>`]);if(isTruth){if(item.truth_type||item.truthType)fields.push(['Truth Type',esc(item.truth_type||item.truthType)]);if(item.category)fields.push(['Category',esc(item.category)]);if(item.origin)fields.push(['Origin',esc(item.origin)]);if(item.confidence_label||item.confidenceLabel)fields.push(['Confidence',esc(item.confidence_label||item.confidenceLabel)]);const rep=item.repetition_score??item.repetitionScore??null;if(rep!=null)fields.push(['Repetitions',esc(rep)]);const ps=item.pressure_score??item.pressureScore??null;if(ps!=null)fields.push(['Pressure Score',esc(ps)]);const cc=item.converted_claim_count??item.convertedClaimCount??null;if(cc!=null)fields.push(['Converted Claims',esc(cc)]);const linked=item.linked_claim_id||item.linkedClaimId||null;if(linked)fields.push(['Linked Claim',`<button class="btn-link-small" onclick="openReviewClaimStudy('${esc(linked)}')">${esc(linked)} ↗</button>`]);}else{if(item.status)fields.push(['Status',esc(item.status)]);if(item.category)fields.push(['Category',esc(item.category)]);if(item.type)fields.push(['Claim Type',esc(item.type)]);if(item.handle)fields.push(['Submitted By',esc(item.handle)]);const es=item.evidence_score??item.evidenceScore??null;if(es!=null)fields.push(['Evidence',`${esc(es)}/100`]);const ts=item.testability??null;if(ts!=null)fields.push(['Testability',`${esc(ts)}/100`]);const sv=item.survivability??null;if(sv!=null)fields.push(['Survivability',`${esc(sv)}/100`]);const contra=item.contradictions??0;if(contra>0)fields.push(['Pressure Points',esc(contra)]);if(item.damage)fields.push(['Damage',esc(item.damage)]);const dup=item.duplicate_of||item.duplicateOf||null;if(dup)fields.push(['Duplicate Of',esc(dup)]);}const created=item.created_at||item.createdAt||null;if(created)fields.push(['Created',new Date(created).toLocaleString()]);const updated=item.updated_at||item.updatedAt||null;if(updated)fields.push(['Updated',new Date(updated).toLocaleString()]);const fieldsHtml=fields.map(([k,v])=>`<div class="review-inspect-field"><span class="review-inspect-label">${k}</span><span class="review-inspect-val">${v}</span></div>`).join('');const studyBtn=!isTruth?`<button class="primary btn-study-review" onclick="openReviewClaimStudy('${esc(id)}')">Open Study View ↗</button>`:isTruth&&(item.linked_claim_id||item.linkedClaimId)?`<button class="btn-study-review" onclick="openReviewClaimStudy('${esc(item.linked_claim_id||item.linkedClaimId)}')">Study Linked Claim ↗</button>`:'';return`<div class="review-inspect-panel" style="grid-column:1/-1"><div class="review-inspect-header"><div class="review-inspect-title-row"><span class="badge ${isTruth?'b-yellow':'b-blue'}">${esc(type)}</span><h3 class="review-inspect-title">${esc(cleanClaimLabel(title))}</h3></div><button class="btn-close-inspect" onclick="inspectReviewItem('${esc(id)}')" title="Close panel">✕ Close</button></div><div class="review-inspect-fields">${fieldsHtml||'<p class="small">Only preview data available for this item.</p>'}</div><div class="review-inspect-actions">${studyBtn}<button onclick="reviewDecisionUI('${esc(type)}','${esc(id)}','public')">Approve Public</button><button onclick="reviewDecisionUI('${esc(type)}','${esc(id)}','review')">Keep Review</button><button class="review-inspect-reject" onclick="reviewDecisionUI('${esc(type)}','${esc(id)}','rejected')">Reject</button></div></div>`}
async function openReviewClaimStudy(id){await selectClaim(id)}
async function saveAdminTokenAndLoadReview(){const token=document.getElementById('adminToken')?.value||'';localStorage.setItem(LS_ADMIN,token);await renderReview()}
function clearAdminToken(){localStorage.removeItem(LS_ADMIN);reviewQueue={claims:[],truths:[],review:[]};renderReview()}
async function reviewDecisionUI(targetType,targetId,decision){const item=(reviewQueue.review||[]).find(i=>i.id===targetId);const raw=item?(item.statement||item.claim||targetId):'item';const label=String(raw).slice(0,48)+(String(raw).length>48?'…':'');const msgs={public:`Approved — "${label}" is now public`,rejected:`Rejected — "${label}" hidden from public`,review:`Kept in review — "${label}" not yet public`};try{await api('/api/review/decision',{method:'POST',headers:adminHeaders(),body:JSON.stringify({targetType,targetId,decision})});toast(msgs[decision]||`Review set to ${decision}`);loadGraphStatus().catch(()=>{});await loadReviewQueue();renderReviewList()}catch(e){toast(e.message||'Review action failed')}}
async function attachEvidencePrompt(evidenceId){if(!claims.length)await loadClaims(false);if(!claims.length)return toast('No claims available to attach to.');attachingEvidenceId=evidenceId;const modal=document.getElementById('attach-modal');if(!modal)return;const opts=claims.map((c,i)=>`<option value="${i}">${esc(cleanClaimLabel(c.claim))}</option>`).join('');modal.innerHTML=`<div class="attach-modal-inner"><h3>Attach to Claim</h3><p class="small">Choose a claim and how this evidence should be attached.</p><select id="attach-claim-select" style="margin-bottom:2px">${opts}</select><div class="attach-stance-row"><button class="btn-approve" onclick="doAttachEvidence('support')">Attach as Support</button><button class="btn-reject" onclick="doAttachEvidence('pressure')">Attach as Pressure</button><button class="btn-keep" onclick="closeAttachModal()">Cancel</button></div></div>`;modal.style.display='flex';}
async function doAttachEvidence(stance){const select=document.getElementById('attach-claim-select');if(!select)return;const target=claims[Number(select.value)];if(!target)return toast('Invalid claim selection');const id=attachingEvidenceId;closeAttachModal();try{await api('/api/evidence-attach',{method:'POST',body:JSON.stringify({evidenceId:id,claimId:target.id,stance})});await loadGraphStatus();toast(`Evidence attached as ${stance}`)}catch(e){toast(e.message||'Could not attach evidence')}}
function closeAttachModal(){const modal=document.getElementById('attach-modal');if(modal)modal.style.display='none';attachingEvidenceId=null;}
async function submitTruth(){const statement=document.getElementById('truthStatement')?.value||'';const category=document.getElementById('truthCategory')?.value||'general';const origin=document.getElementById('truthOrigin')?.value||'unknown';const truthType=document.getElementById('truthType')?.value||'common';try{await api('/api/truths',{method:'POST',body:JSON.stringify({statement,category,origin,truthType})});await loadGraphStatus();toast('Truth recorded');await renderTruths()}catch(e){toast(e.message)}}
function renderExport(){document.body.classList.remove('study-mode');document.getElementById('casefile').innerHTML=helperText();document.getElementById('side-tools').style.display='none';document.getElementById('main').innerHTML=`<div class="panel form-panel"><h2>RunPack Export</h2><p class="small">Open a claim in Study mode, generate its RunPack, then paste into any AI for external analysis. Public use does not consume owner API credits.</p><div class="actions"><button class="primary" onclick="generateRunPack()">Generate RunPack</button><button onclick="downloadJSON()">Download visible data JSON</button></div><pre class="output">${esc(selected?JSON.stringify({selected},null,2):'No selected claim. Open a claim first.')}</pre></div>`}
async function selectClaim(id){try{const data=await api('/api/claims/'+id);selected=data.claim;selected.claim=cleanClaimLabel(selected.claim);selected.evidence=data.evidence||[];selected.pressure=data.pressure||[];selected.tests=data.tests||data.home_tests||[];selected.analyses=data.analyses||[];selected.lineage=data.lineage||null;renderStudy();toast('Study loaded')}catch(e){const fallback=claims.find(c=>c.id===id)||selected;if(fallback){selected=fallback;selected.analyses=selected.analyses||[];selected.lineage=selected.lineage||null;renderStudy()}toast(e.message||'Could not load claim')}}
function renderStudy(){if(!selected)return;document.body.classList.add('study-mode');document.getElementById('side-tools').style.display='block';const studyMeta=[selected.category,selected.type,selected.handle?'by '+selected.handle:''].filter(Boolean).map(esc).join(' · ');document.getElementById('main').innerHTML=`<div class="study"><div class="study-header"><div class="study-nav"><button onclick="backToArena()">← Back</button><span class="badge ${cls(selected.status)}">${esc(selected.status||'unknown')}</span></div><h2>${esc(cleanClaimLabel(selected.claim))}</h2>${studyMeta?`<p class="study-meta small">${studyMeta}</p>`:''}<div class="meters wide">${meter('Evidence',selected.evidenceScore)}${meter('Testability',selected.testability)}${meter('Survivability',selected.survivability)}</div><div class="study-vote-row"><div class="study-votes"><button class="vote yes" onclick="voteClaim('believe')">▲ Believe</button><button class="vote no" onclick="voteClaim('reject')">▼ Reject</button><button class="vote unsure" onclick="voteClaim('unsure')">~ Unsure</button></div><div class="study-actions"><button class="primary" onclick="generateRunPack()">Generate RunPack</button></div></div></div>${sectionLineage()}${sectionArgumentFlow()}<div class="inv-board-head"><span>Investigation Board</span></div><div class="study-grid"><section class="panel evidence-panel">${sectionEvidence()}</section><section class="panel pressure-panel">${sectionPressure()}</section><section class="panel tests-panel">${sectionTests()}</section><section class="panel analysis-panel">${sectionAnalyses()}</section></div></div>`;renderCaseMini()}
function renderCaseMini(){const l=selected?.lineage||{};document.getElementById('casefile').innerHTML=`<p class="small"><b>Selected claim</b><br>${esc(cleanClaimLabel(selected.claim))}</p><p class="small">Lineage: ${esc((l.truths||[]).length)} truth · ${esc((l.evidenceLinks||[]).length)} evidence · ${esc(l.pressureCount||0)} pressure · ${esc(l.analysisCount||0)} analysis.</p><p class="small">Study flow: support → pressure → tests → analysis.</p><p class="small">Add evidence or pressure from this panel. Generate a RunPack to export the claim for AI analysis.</p>`}
function evidenceMeta(e){const reused=e.link_type==='reused';const stance=e.linked_stance||e.stance||'support';return`${reused?'REUSED · ':''}${esc(e.quality||e.stance)} · ${esc(e.media_type||e.mediaType||'text')} · ${esc(stance)} · reliability ${esc(e.reliability_score||e.reliabilityScore||'?')}`}
function evidenceItem(e){const a=parseAnalysis(e.body||e.note);if(a)return`<div class="row analysis-card"><div class="inv-item-head"><b class="inv-item-title">${esc(e.title)}</b><span class="badge ${cls(a.verdict)}">${esc(a.verdict||'analysis')}</span><span class="pill">legacy</span></div><div class="meters">${meter('Evidence',a.evidence_score||0)}${meter('Test',a.testability||0)}${meter('Survive',a.survivability||0)}</div><p class="small">${esc(a.plain_language_summary||'Structured AIP/AI analysis stored in old evidence field.')}</p><details><summary>Support / pressure / missing tests</summary><h4>Support</h4>${listBits(a.strongest_support)}<h4>Pressure</h4>${listBits(a.strongest_pressure)}<h4>Missing tests</h4>${listBits(a.missing_tests)}</details></div>`;return`<div class="row"><div class="inv-item-head"><b class="inv-item-title">${esc(e.title)}</b><span class="pill">${evidenceMeta(e)}</span></div><p class="small">${esc(shortText(e.body||e.note,620))}</p>${e.link_note?`<p class="small"><b>Reuse:</b> ${esc(e.link_note)}</p>`:''}${sourceLink(e.source_url||e.sourceUrl)}</div>`}
function analysisItem(a){const raw=a.raw||a;const verdict=a.verdict||raw.verdict||'analysis';const summary=a.plainLanguageSummary||raw.plain_language_summary||'Stored analysis result.';const src=a.source||raw.source||'runpack-user';return`<div class="analysis-result-card"><div class="inv-item-head"><span class="badge ${cls(verdict)}">${esc(verdict)}</span><span class="pill">${esc(src)}</span></div><div class="meters">${meter('Evidence',a.evidenceScore||raw.evidence_score||0)}${meter('Test',a.testability||raw.testability||0)}${meter('Survive',a.survivability||raw.survivability||0)}</div><p class="small">${esc(summary)}</p><details class="analysis-details"><summary>Support · Pressure · Missing tests</summary><div class="analysis-detail-grid"><div><h4>Support</h4>${listBits(a.strongestSupport||raw.strongest_support)}</div><div><h4>Pressure</h4>${listBits(a.strongestPressure||raw.strongest_pressure)}</div><div><h4>Missing tests</h4>${listBits(a.missingTests||raw.missing_tests)}</div></div></details></div>`}
function sectionLineage(){const l=selected?.lineage||{};const truths=l.truths||[];const evidenceLinks=l.evidenceLinks||[];return`<section class="panel lineage-panel"><div class="section-head"><h3>Lineage</h3><span class="badge b-blue">Belief → Truth → Claim → Evidence</span></div><div class="graph-status"><span><b>${esc((l.beliefs||[]).length)}</b><small>Beliefs</small></span><span><b>${esc(truths.length)}</b><small>Truths</small></span><span><b>1</b><small>Claim</small></span><span><b>${esc(evidenceLinks.length)}</b><small>Evidence</small></span><span><b>${esc(l.pressureCount||0)}</b><small>Pressure</small></span><span><b>${esc(l.testCount||0)}</b><small>Tests</small></span><span><b>${esc(l.analysisCount||0)}</b><small>Analysis</small></span></div>${truths.length?`<div class="row"><span class="pill">upstream truth</span>${truths.slice(0,3).map(t=>`<p class="small"><b>${esc(cleanClaimLabel(t.statement||'Truth'))}</b><br>${esc(t.bridge_note||t.origin||'Linked truth')}</p>`).join('')}</div>`:'<p class="small">No upstream truth linked yet. This claim may have been submitted directly or promoted from a belief without a formal truth bridge.</p>'}</section>`}
function firstEvidence(){return(selected.evidence||[]).find(e=>!parseAnalysis(e.body||e.note))}
function firstPressure(){return(selected.pressure||[])[0]}
function firstTest(){return(selected.tests||[])[0]}
function firstAnalysis(){return(selected.analyses||[])[0]}
function sectionArgumentFlow(){const e=firstEvidence(),p=firstPressure(),t=firstTest(),a=firstAnalysis();const raw=a?.raw||a||{};return`<section class="panel flow-panel"><div class="section-head"><h3>Claim Flow</h3><span class="badge b-green">read this first</span></div><div class="flow-steps"><div class="row"><span class="pill">1 · Why people think it is true</span><p class="small">${e?`<b>${esc(e.title||'Evidence')}</b><br>${esc(shortText(e.body||e.note,260))}`:'No support evidence attached yet — add one from the side panel.'}</p></div><div class="row"><span class="pill">2 · What attacks it</span><p class="small">${p?`<b>${esc(p.title||'Pressure')}</b><br>${esc(shortText(p.body||p.note,260))}`:'No pressure attached yet — add an objection from the side panel.'}</p></div><div class="row"><span class="pill">3 · How to test it</span><p class="small">${t?`<b>${esc(t.title||'Test')}</b><br>${esc(shortText(t.instructions,260))}`:'No test added yet — add one in the Tests section below.'}</p></div><div class="row"><span class="pill">4 · What analysis says</span><p class="small">${a?`<b>${esc(a.verdict||raw.verdict||'Analysis')}</b><br>${esc(shortText(a.plainLanguageSummary||raw.plain_language_summary||'Stored analysis result.',260))}`:'No analysis saved yet — generate a RunPack and paste the result below.'}</p></div></div></section>`}
function sectionEvidence(){const ev=selected.evidence||[];return`<div class="inv-sec-head"><div class="inv-sec-title"><h3>Support Evidence</h3><span class="badge b-blue">${ev.length} item${ev.length===1?'':'s'}</span></div><p class="inv-sec-purpose">What currently supports this claim.</p></div>${ev.map(evidenceItem).join('')||'<div class="empty-state"><p>No supporting evidence attached yet.</p><p class="small">Add a source, document, or reused vault item from the side panel.</p></div>'}`}
function sectionPressure(){const pr=selected.pressure||[];return`<div class="inv-sec-head"><div class="inv-sec-title"><h3>Pressure / Attacks</h3><span class="badge b-yellow">${pr.length} item${pr.length===1?'':'s'}</span></div><p class="inv-sec-purpose">What challenges, contradicts, or weakens it.</p></div>${pr.map(p=>{const a=parseAnalysis(p.body||p.note);return a?`<div class="row analysis-card"><div class="inv-item-head"><b class="inv-item-title">${esc(p.title)}</b><span class="badge ${cls(a.verdict||'analysis')}">${esc(a.verdict||'analysis')}</span><span class="pill">legacy</span></div><p class="small">${esc(a.plain_language_summary||'Structured analysis pressure result.')}</p>${listBits(a.strongest_pressure)}</div>`:`<div class="row"><div class="inv-item-head"><b class="inv-item-title">${esc(p.title)}</b><span class="pill">severity ${esc(p.severity||1)}</span></div><p class="small">${esc(shortText(p.body||p.note,620))}</p></div>`}).join('')||'<div class="empty-state"><p>No pressure attached yet.</p><p class="small">Add an objection, contradiction, or attack from the side panel.</p></div>'}`}
function sectionTests(){const ts=selected.tests||[];return`<div class="inv-sec-head"><div class="inv-sec-title"><h3>Tests</h3><span class="badge b-green">${ts.length} test${ts.length===1?'':'s'}</span></div><p class="inv-sec-purpose">Ways this claim could be checked or falsified.</p></div><div class="test-add-form"><input id="testTitle" placeholder="Test title"><textarea id="testInstructions" placeholder="Instructions: what to do, what to record, how to repeat it"></textarea><div class="test-form-row"><select id="testSafety"><option value="low">low safety risk</option><option value="medium">medium safety risk</option><option value="high">high safety risk</option></select><select id="testDifficulty"><option value="easy">easy</option><option value="medium">medium</option><option value="hard">hard</option></select></div><button class="primary" onclick="addHomeTestUI()">Add Test</button></div>${ts.map(t=>`<div class="test-item"><div class="inv-item-head"><b class="inv-item-title">${esc(t.title)}</b><span class="pill">${esc(t.difficulty||'test')} · ${esc(t.safety_level||t.safetyLevel||'normal')}</span></div><p class="small">${esc(t.instructions)}</p></div>`).join('')||'<div class="empty-state"><p>No tests added yet.</p><p class="small">A test describes how this claim could be verified or falsified. Use the form above to add one.</p></div>'}`}
function sectionAnalyses(){const an=selected.analyses||[];return`<div class="inv-sec-head"><div class="inv-sec-title"><h3>Analysis</h3><span class="badge b-blue">${an.length} result${an.length===1?'':'s'}</span></div><p class="inv-sec-purpose">Saved RunPack or AI analysis results.</p></div><div class="analysis-save-form"><p class="small">Generate a RunPack above → paste into any AI → paste the JSON result here.</p><textarea id="analysisPaste" placeholder="Paste RunPack output JSON here"></textarea><div class="actions"><button class="primary" onclick="saveAnalysisResult()">Save Analysis</button></div></div>${an.map(analysisItem).join('')||'<div class="empty-state"><p>No analysis saved yet.</p><p class="small">Generate a RunPack and paste the JSON result into the field above to save it against this claim.</p></div>'}`}
function backToArena(){document.body.classList.remove('study-mode');selected=null;setMode('arena')}
async function voteClaim(vote){if(!selected)return toast('Select a claim first');try{const data=await api('/api/claim-vote',{method:'POST',body:JSON.stringify({claimId:selected.id,vote})});selected=data.claim||selected;toast('Vote recorded');await loadGraphStatus();await loadClaims(false);await selectClaim(selected.id)}catch(e){toast(e.message||'Vote route not wired yet')}}
async function saveClaim(){const body={claim:document.getElementById('cClaim').value,category:document.getElementById('cCategory').value,type:document.getElementById('cType').value,initialEvidence:document.getElementById('cEvidence').value};try{const data=await api('/api/claims',{method:'POST',body:JSON.stringify(body)});selected=data.claim;await loadGraphStatus();await loadClaims(false);toast('Claim received');document.getElementById('main').innerHTML=`<div class="panel form-panel"><span class="badge b-yellow">in review</span><h2>Claim received</h2><p class="small">Your claim is now in the moderation queue. It may not appear publicly until an admin approves it.</p><p class="small"><b>${esc(cleanClaimLabel(selected.claim))}</b></p><div class="actions"><button class="primary" onclick="selectClaim('${esc(selected.id)}')">Study this claim</button><button onclick="setMode('submit')">Submit another</button><button onclick="setMode('arena')">Browse Claims</button></div></div>`}catch(e){toast(e.message)}}
async function addCaseItem(){if(!selected)return toast('Select a claim first');const kind=document.getElementById('eKind').value;const payload={claimId:selected.id,title:document.getElementById('eTitle').value,quality:document.getElementById('eQuality').value,body:document.getElementById('eNote').value,sourceUrl:document.getElementById('eSource')?.value||''};try{const data=await api(kind==='evidence'?'/api/evidence':'/api/pressure',{method:'POST',body:JSON.stringify(payload)});selected=data.claim||selected;await loadGraphStatus();await selectClaim(selected.id);document.getElementById('eTitle').value='';document.getElementById('eNote').value='';if(document.getElementById('eSource'))document.getElementById('eSource').value='';toast(kind==='evidence'?'Evidence attached':'Pressure attached')}catch(e){toast(e.message)}}
async function addHomeTestUI(){if(!selected)return toast('Select a claim first');const title=(document.getElementById('testTitle')?.value||'').trim();const instructions=(document.getElementById('testInstructions')?.value||'').trim();if(!title)return toast('Enter a test title before adding.');if(instructions.length<8)return toast('Instructions need at least 8 characters — describe what to do and record.');const body={claimId:selected.id,title,instructions,safetyLevel:document.getElementById('testSafety')?.value||'low',difficulty:document.getElementById('testDifficulty')?.value||'easy'};try{await api('/api/tests',{method:'POST',body:JSON.stringify(body)});toast('Test added');await selectClaim(selected.id)}catch(e){toast(e.message||'Could not add test')}}
async function reportSelected(){if(!selected)return toast('Select a claim first');const reason=prompt('Why report this claim?');if(!reason)return;try{await api('/api/report',{method:'POST',body:JSON.stringify({targetType:'claim',targetId:selected.id,reason})});await loadGraphStatus();toast('Report sent')}catch(e){toast(e.message)}}
async function convertTruth(truthId){try{const data=await api('/api/truth-to-claim',{method:'POST',body:JSON.stringify({truthId})});toast(data.existing?'Existing claim opened':'Truth converted');mode='arena';await loadGraphStatus();await loadClaims(false);if(data.bridge?.claimId)await selectClaim(data.bridge.claimId)}catch(e){toast(e.message||'Could not convert truth')}}
async function generateRunPack(){if(!selected)return toast('Open a claim first');try{const data=await api('/api/runpack',{method:'POST',body:JSON.stringify({claimId:selected.id})});lastPacket=JSON.stringify(data.packet,null,2)}catch(e){lastPacket=JSON.stringify({runpack_version:'1.1',legacy_aip_version:'1.1',aip_version:'1.1',packet_type:'runpack_task',app:'HumanX',mode:'claim-pressure-analysis',no_owner_api_used:true,payload:selected},null,2)}const out=document.getElementById('aip');if(out)out.textContent=lastPacket;toast('RunPack ready — copy it into your AI')}
async function generateAIP(){return generateRunPack()}
async function copyAIP(){if(!lastPacket)await generateRunPack();navigator.clipboard.writeText(lastPacket);toast('RunPack copied')}
async function saveAnalysisResult(){if(!selected)return toast('Open a claim first');const box=document.getElementById('analysisPaste');const text=box?.value||'';let parsed;try{parsed=JSON.parse(text)}catch(e){return toast('Paste valid JSON first')}const result=parsed.output||parsed.result||parsed.analysis||parsed;try{await api('/api/analysis',{method:'POST',body:JSON.stringify({claimId:selected.id,source:'runpack-user',raw:result})});if(box)box.value='';toast('Analysis saved');await selectClaim(selected.id)}catch(e){toast(e.message||'Could not save analysis')}}
function downloadJSON(){const blob=new Blob([JSON.stringify({user,claims,evidenceVault,truths,beliefSnapshots,graphStatus},null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='humanx-visible-data.json';a.click();URL.revokeObjectURL(a.href)}
function renderError(e){document.getElementById('main').innerHTML=`<div class="panel"><h2>HumanX backend notice</h2><p class="small">${esc(e.message||e)}</p></div>`}
window.setMode=setMode;window.searchCurrent=searchCurrent;window.loadClaims=loadClaims;window.saveAdminTokenAndLoadReview=saveAdminTokenAndLoadReview;window.clearAdminToken=clearAdminToken;window.reviewDecisionUI=reviewDecisionUI;window.inspectReviewItem=inspectReviewItem;window.openReviewClaimStudy=openReviewClaimStudy;window.setReviewFilter=setReviewFilter;window.selectClaim=selectClaim;window.saveClaim=saveClaim;window.addCaseItem=addCaseItem;window.addHomeTestUI=addHomeTestUI;window.reportSelected=reportSelected;window.generateAIP=generateAIP;window.generateRunPack=generateRunPack;window.copyAIP=copyAIP;window.downloadJSON=downloadJSON;window.voteClaim=voteClaim;window.backToArena=backToArena;window.submitTruth=submitTruth;window.convertTruth=convertTruth;window.attachEvidencePrompt=attachEvidencePrompt;window.doAttachEvidence=doAttachEvidence;window.closeAttachModal=closeAttachModal;window.saveBeliefMirror=saveBeliefMirror;window.beliefPreview=beliefPreview;window.promoteBelief=promoteBelief;window.saveAnalysisResult=saveAnalysisResult;
boot();
